solutions.python:
class Solution:
    def solve(self):
        pipeline = [
            # Project the 'name' and 'age' fields, excluding the 'address' field
            { '$project': { 'name': 1, 'age': 1, 'address': 0 } }
        ]

        # Define the collection to aggregate
        collection = [
            { 'name': 'John', 'age': 30, 'address': { 'street': '123 Main St', 'city': 'Anytown', 'state': 'CA', 'zip': '12345' } }
        ]

        # Implement the aggregation pipeline
        result = list(collection.aggregate(pipeline))

        # Print the result
        print(result)
